UPDATE user_tag_group
name = #{name}, color = #{color}, is_exclusive = #{isExclusive}, is_required = #{isRequired}, sort_order = #{sortOrder}, updated_at = #{updatedAt}
WHERE id = #{id}

UPDATE user_tag_value
`value` = #{value}, color = #{color}, sort_order = #{sortOrder},
WHERE id = #{id}

UPDATE material_tag
SET tag_value = #{newValue}
WHERE tag_group_key = #{groupKey}
  AND tag_value = #{oldValue}
